24	// Stats holds the collected transfer statistics.
25	type Stats struct {
26		Enabled bool                     `json:"enabled"`
27		Items   map[string]*ServiceStats `json:"items"`
28	}
29	
30	// statsCollector is a concurrency-safe stats collector (issue #8).
31	type statsCollector struct {
32		enabled bool
33		mu      sync.Mutex
34		items   map[string]*ServiceStats
35	}
36	
37	func newStats(enabled bool) *statsCollector {
38		return &statsCollector{enabled: enabled, items: map[string]*ServiceStats{}}
39	}
40	
41	func (s *statsCollector) ensure(name string) *ServiceStats {
42		item, ok := s.items[name]
43		if !ok {
44			item = &ServiceStats{Name: name}
45			s.items[name] = item
46		}
47		return item
48	}
49	
50	func (s *statsCollector) recordRoundTrip(name string, requestBytes, responseBytes int64) {
51		if !s.enabled {
52			return
53		}
54		s.mu.Lock()
55		defer s.mu.Unlock()
56		item := s.ensure(name)
57		item.Requests++
58		item.RequestBytes += requestBytes
59		item.ResponseBytes += responseBytes
60	}
61	
62	func (s *statsCollector) snapshot() Stats {
63		s.mu.Lock()
64		defer s.mu.Unlock()
65		out := Stats{Enabled: s.enabled, Items: make(map[string]*ServiceStats, len(s.items))}
66		for key, item := range s.items {
67			copyItem := *item
68			out.Items[key] = &copyItem
69		}
70		return out
71	}
